def test_combinatorial_negatives():
    base_url = "http://localhost:8080"
    path = "/api/v1/enroll"

    # Invalid user_id and password
    resp = requests.post(f"{base_url}{path}", json={"user_id": -1, "password": ""}, timeout=10)
    body = resp.json()
    assert not body.get("success")
    assert body.get("error_code") < 0

    # Missing required fields (user_id and password)
    resp = requests.post(f"{base_url}{path}", json={"password": ""}, timeout=10)
    body = resp.json()
    assert not body.get("success")
    assert body.get("error_code") < 0

